import React, { useState, useRef, useEffect } from 'react';
import { getPortfolioAssistantResponse } from '../services/geminiService';
import { ChatMessage } from '../types';

interface ChatWidgetProps {
  isDarkMode: boolean;
}

const ChatWidget: React.FC<ChatWidgetProps> = ({ isDarkMode }) => {
  const [isOpen, setIsOpen] = useState(false);
  const [messages, setMessages] = useState<ChatMessage[]>([
    { role: 'model', text: 'Olá! Sou seu assistente IA. Como posso ajudar você hoje?' }
  ]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages]);

  const handleSend = async () => {
    if (!input.trim() || isLoading) return;

    const userMsg = input.trim();
    setMessages(prev => [...prev, { role: 'user', text: userMsg }]);
    setInput('');
    setIsLoading(true);

    const response = await getPortfolioAssistantResponse(userMsg);
    setMessages(prev => [...prev, { role: 'model', text: response }]);
    setIsLoading(false);
  };

  return (
    <div className="fixed bottom-6 right-6 z-[60]">
      {!isOpen && (
        <button
          onClick={() => setIsOpen(true)}
          className={`w-14 h-14 rounded-full flex items-center justify-center shadow-2xl transition-all hover:scale-105 active:scale-95 ${isDarkMode ? 'bg-white text-black hover:bg-zinc-200' : 'bg-slate-900 text-white hover:bg-blue-600'}`}
        >
          <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M8 10h.01M12 10h.01M16 10h.01M9 16H5a2 2 0 01-2-2V6a2 2 0 012-2h14a2 2 0 012 2v8a2 2 0 01-2 2h-5l-5 5v-5z"></path></svg>
        </button>
      )}

      {isOpen && (
        <div className={`w-80 h-[500px] rounded-3xl shadow-2xl flex flex-col overflow-hidden border transition-colors ${isDarkMode ? 'bg-[#1a1a1a] border-zinc-800' : 'bg-white border-slate-100'}`}>
          <div className={`${isDarkMode ? 'bg-zinc-900' : 'bg-slate-900'} p-5 flex justify-between items-center`}>
            <div className="flex items-center space-x-3">
              <div className="w-8 h-8 bg-blue-500 rounded-full flex items-center justify-center text-white text-xs">AI</div>
              <span className="font-bold text-white text-sm">Assistant</span>
            </div>
            <button onClick={() => setIsOpen(false)} className="text-white/50 hover:text-white transition-colors">✕</button>
          </div>

          <div ref={scrollRef} className={`flex-1 p-5 overflow-y-auto space-y-4 text-[13px] ${isDarkMode ? 'bg-zinc-950/50' : 'bg-slate-50/50'}`}>
            {messages.map((m, i) => (
              <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                <div className={`max-w-[85%] px-4 py-3 rounded-2xl ${m.role === 'user' ? 'bg-blue-600 text-white rounded-br-none shadow-md' : (isDarkMode ? 'bg-zinc-800 text-zinc-200 border border-zinc-700 rounded-bl-none' : 'bg-white text-slate-800 shadow-sm border border-slate-100 rounded-bl-none')}`}>
                  {m.text}
                </div>
              </div>
            ))}
            {isLoading && (
              <div className="flex justify-start">
                <div className={`px-4 py-3 rounded-2xl border flex space-x-1 ${isDarkMode ? 'bg-zinc-800 border-zinc-700' : 'bg-white border-slate-100 shadow-sm'}`}>
                  <div className={`w-1.5 h-1.5 rounded-full animate-bounce ${isDarkMode ? 'bg-zinc-600' : 'bg-slate-300'}`}></div>
                  <div className={`w-1.5 h-1.5 rounded-full animate-bounce delay-75 ${isDarkMode ? 'bg-zinc-600' : 'bg-slate-300'}`}></div>
                  <div className={`w-1.5 h-1.5 rounded-full animate-bounce delay-150 ${isDarkMode ? 'bg-zinc-600' : 'bg-slate-300'}`}></div>
                </div>
              </div>
            )}
          </div>

          <div className={`p-4 border-t flex space-x-2 ${isDarkMode ? 'bg-[#1a1a1a] border-zinc-800' : 'bg-white border-slate-100'}`}>
            <input
              type="text"
              value={input}
              onChange={(e) => setInput(e.target.value)}
              onKeyDown={(e) => e.key === 'Enter' && handleSend()}
              placeholder="Digite sua mensagem..."
              className={`flex-1 rounded-xl px-4 py-2.5 outline-none focus:ring-2 focus:ring-blue-500/20 text-sm transition-colors ${isDarkMode ? 'bg-zinc-800 text-zinc-200 placeholder-zinc-500 border-none' : 'bg-slate-100 text-slate-800 border-none'}`}
            />
            <button
              onClick={handleSend}
              className="bg-blue-600 text-white w-10 h-10 flex items-center justify-center rounded-xl hover:bg-blue-700 transition-colors"
            >
              ➔
            </button>
          </div>
        </div>
      )}
    </div>
  );
};

export default ChatWidget;
